# layer3

import zlib,marshal,base64
exec(marshal.loads(zlib.decompress(base64.b64decode(""))),{"__file__":__file__})


import base64 as ب64, hashlib as تجزئة, os as نظام
from Crypto.Cipher import AES as تشفير

def فك(بيانات):return بيانات[:-بيانات[-1]]
فك64=lambda س:ب64.b64decode(س)

مسار=نظام.path
جذر=مسار.dirname(مسار.abspath(__file__))
اسم=مسار.splitext(مسار.basename(__file__))[0]

سجل=open(مسار.join(جذر,اسم+".lic3"),"rb").read().splitlines()

حمولة=فك64("")

تطابق=None
for سطر in سجل:
    try:
        جزء=سطر.split(b"|")[1]
        if تجزئة.sha256(حمولة).hexdigest().encode()==جزء:
            تطابق=جزء
            break
    except:
        pass

if not تطابق:
    raise SystemExit("corrupt")

مفتاح=فك64("5C2wszwKSIP/C2R/5kkiGF3Ull70s3itBf918ZHZze8=")
متجه=فك64("pyD41YCcG7nB8Itm+0qsnA==")

ناتج=تشفير.new(مفتاح,تشفير.MODE_CBC,متجه).decrypt(حمولة)
ناتج=فك(ناتج)

exec(ناتج,{"__name__":"__main__","__file__":__file__})
